package il.co.dcd.composermapper.render; import il.co.dcd.composermapper.model.ContextDef; import il.co.dcd.composermapper.util.FileUtil; import java.nio.file.Path; import java.io.IOException;
public class ContextMarkdownWriter { public void write(ContextDef c, Path vault){ Path out=vault.resolve("contexts").resolve(c.getId()+".md"); StringBuilder sb=new StringBuilder(); sb.append("# ").append(c.getId()).append("\n\n---\nentity_type: context\nentity_id: ").append(c.getId()).append("\nsource_file: ").append(c.getSourceFile()).append("\nsource_hash: ").append(FileUtil.sha256(c.getSourceFile())).append("\n---\n\n## Details\n"); sb.append(MarkdownSupport.bullet("parent: "+MarkdownSupport.code(String.valueOf(c.getParent())))); sb.append(MarkdownSupport.bullet("type: "+MarkdownSupport.code(String.valueOf(c.getType())))); sb.append("\n## Raw Attributes\n"); c.getRawAttributes().forEach((k,v)->sb.append(MarkdownSupport.bullet(k+": "+MarkdownSupport.code(v)))); try{ FileUtil.writeString(out,sb.toString()); }catch(IOException e){ throw new RuntimeException(e);} } }
